    message: 'Backup file rusak',
    statusCode: 500,
    recoveryTip: 'Gunakan backup file yang lain'
  },
  
  // Scraper Errors
  [ErrorCode.SCRAPER_SOURCE_NOT_FOUND]: {
    code: ErrorCode.SCRAPER_SOURCE_NOT_FOUND,
    message: 'Scraper source tidak ditemukan',
    statusCode: 404,
    recoveryTip: 'Periksa kembali scraper source ID'
  },
  [ErrorCode.SCRAPER_EXECUTION_FAILED]: {
    code: ErrorCode.SCRAPER_EXECUTION_FAILED,
    message: 'Gagal menjalankan scraper',
    statusCode: 500,
    recoveryTip: 'Coba lagi atau periksa konfigurasi scraper'
  },
  [ErrorCode.SCRAPER_TIMEOUT]: {
    code: ErrorCode.SCRAPER_TIMEOUT,
    message: 'Scraper timeout',
    statusCode: 504,
    recoveryTip: 'Coba jalankan scraper lagi'
  },
  [ErrorCode.SCRAPER_RATE_LIMITED]: {
    code: ErrorCode.SCRAPER_RATE_LIMITED,
    message: 'Scraper rate limited oleh target website',
    statusCode: 429,
    recoveryTip: 'Tunggu beberapa saat sebelum mencoba lagi'
  },
  [ErrorCode.SCRAPER_INVALID_CONFIG]: {
    code: ErrorCode.SCRAPER_INVALID_CONFIG,
    message: 'Konfigurasi scraper tidak valid',
    statusCode: 400,
    recoveryTip: 'Periksa kembali konfigurasi scraper'
  },
  
  // Database Errors
  [ErrorCode.DATABASE_CONNECTION_ERROR]: {
    code: ErrorCode.DATABASE_CONNECTION_ERROR,
    message: 'Gagal koneksi ke database',
    statusCode: 500,
    recoveryTip: 'Coba lagi dalam beberapa saat'
  },
  [ErrorCode.DATABASE_QUERY_ERROR]: {
    code: ErrorCode.DATABASE_QUERY_ERROR,
    message: 'Gagal menjalankan query database',
    statusCode: 500,
    recoveryTip: 'Coba lagi dalam beberapa saat'
  },
  [ErrorCode.DATABASE_CONSTRAINT_ERROR]: {
    code: ErrorCode.DATABASE_CONSTRAINT_ERROR,
    message: 'Data melanggar constraint database',
    statusCode: 400,
    recoveryTip: 'Periksa kembali data yang Anda kirim'
  },
  [ErrorCode.DATABASE_TRANSACTION_ERROR]: {
    code: ErrorCode.DATABASE_TRANSACTION_ERROR,
    message: 'Gagal menjalankan transaksi database',
    statusCode: 500,
    recoveryTip: 'Coba lagi dalam beberapa saat'
  },
  
  // File Upload Errors
  [ErrorCode.FILE_TOO_LARGE]: {
    code: ErrorCode.FILE_TOO_LARGE,
    message: 'File terlalu besar',
    statusCode: 413,
    recoveryTip: 'Gunakan file dengan ukuran lebih kecil (maksimal 5MB)'
  },
  [ErrorCode.FILE_INVALID_TYPE]: {
    code: ErrorCode.FILE_INVALID_TYPE,
    message: 'Tipe file tidak valid',
    statusCode: 400,
    recoveryTip: 'Gunakan tipe file yang didukung'
  },
  [ErrorCode.FILE_UPLOAD_FAILED]: {
    code: ErrorCode.FILE_UPLOAD_FAILED,
    message: 'Gagal upload file',
    statusCode: 500,
    recoveryTip: 'Coba lagi dalam beberapa saat'
  },
  
  // Analytics Errors
  [ErrorCode.ANALYTICS_TRACKING_FAILED]: {
    code: ErrorCode.ANALYTICS_TRACKING_FAILED,
    message: 'Gagal tracking analytics',
    statusCode: 500,
    recoveryTip: 'Coba lagi dalam beberapa saat'
  },
  [ErrorCode.ANALYTICS_QUERY_FAILED]: {
    code: ErrorCode.ANALYTICS_QUERY_FAILED,
    message: 'Gagal query analytics data',
    statusCode: 500,
    recoveryTip: 'Coba lagi dalam beberapa saat'
  },
  
  // SEO Errors
  [ErrorCode.SEO_SITEMAP_GENERATION_FAILED]: {
    code: ErrorCode.SEO_SITEMAP_GENERATION_FAILED,
    message: 'Gagal generate sitemap',
    statusCode: 500,
    recoveryTip: 'Coba lagi dalam beberapa saat'
  },
  [ErrorCode.SEO_REDIRECT_NOT_FOUND]: {
    code: ErrorCode.SEO_REDIRECT_NOT_FOUND,
    message: 'Redirect tidak ditemukan',
    statusCode: 404,
    recoveryTip: 'Periksa kembali redirect ID'
  },
  [ErrorCode.SEO_REDIRECT_ALREADY_EXISTS]: {
    code: ErrorCode.SEO_REDIRECT_ALREADY_EXISTS,
    message: 'Redirect sudah ada',
    statusCode: 409,
    recoveryTip: 'Gunakan URL yang berbeda'
  },
};

/**
 * Get error definition by code
 */
export function getErrorDefinition(code: ErrorCode): ErrorDefinition {
  return ERROR_DEFINITIONS[code] || ERROR_DEFINITIONS[ErrorCode.INTERNAL_SERVER_ERROR];
}

/**
 * Application Error Class
 */
export class AppError extends Error {
  public readonly code: ErrorCode;
  public readonly statusCode: number;
  public readonly recoverySuggestion?: string;
  public readonly context?: Record<string, any>;

  constructor(
    code: ErrorCode,
    message?: string,
    context?: Record<string, any>
  ) {
    super(message || ErrorMessages[code]);
    this.name = 'AppError';
    this.code = code;
    this.statusCode = ErrorStatusCodes[code];
    this.recoverySuggestion = ErrorRecoverySuggestions[code];
    this.context = context;

    // Maintains proper stack trace for where our error was thrown
    Error.captureStackTrace(this, this.constructor);
  }

  /**
   * Convert to JSON for API response
   */
  toJSON() {
    return {
      success: false,
      error: {
        code: this.code,
        message: this.message,
        recoverySuggestion: this.recoverySuggestion,
        ...(process.env.NODE_ENV === 'development' && {
          stack: this.stack,
          context: this.context
        })
      }
    };
  }
}

/**
 * Helper function to create AppError
 */
export function createError(
  code: ErrorCode,
  message?: string,
  context?: Record<string, any>
): AppError {
  return new AppError(code, message, context);
}

toolSpecification.description:
Read and analyze code files. For small files (<10k chars), returns full content. For larger files, uses AST parsing to extract signatures.

IMPORTANT: Prefer this tool over readFile for code files unless you need specific line ranges. This tool intelligently handles file size and provides structured code analysis.

CORE FEATURES:
• Auto-detects file size and chooses best approach
• Small files: Returns complete file content
• Large files: Extracts function/class signatures via AST
• Fuzzy search for symbols (classes, functions, methods)
• Scoped method search (Class.method syntax)
• Supports: classes, functions, methods, arrow functions, generators

BEHAVIOR:
• File <10k chars: Returns full file content (selector ignored)
• File ≥10k chars + no selector: Returns all signatures
• File ≥10k chars + selector: Searches for selector, shows implementation
• Directory: Returns signatures from code files

SUPPORTED PATTERNS:
• Traditional functions: function foo() {}
• Arrow functions: const foo = () => {}
• Async functions: async function foo() {}, const foo = async () => {}
• Generator functions: function* foo() {}, *methodName() {}, async *methodName() {}
• Class properties with arrow functions: filter = (x) => x
• Getters/setters: get status() {}, set status(v) {}
• Abstract classes: abstract class Base {}
• Nested classes: class Outer { static Inner = class {} }
• Enums: enum Status { Active, Inactive }
• Namespaces: namespace Utils { export class Helper {} }
• Interfaces: interface IData { method(): void }
• Class methods and constructors
• Scoped lookup: ClassName.methodName (single-level only, e.g., MyClass.method)

NOTE: Use readFile with line ranges for not supported patterns.

