 */

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { ScraperQueueService } from './scraperQueueService';
import * as socketManager from './socketManager';

// Mock socketManager
vi.mock('./socketManager', () => ({
  getSocketInstance: vi.fn(() => null),
}));

// Mock logger
vi.mock('./loggerService', () => ({
  logger: {
    info: vi.fn(),
    warn: vi.fn(),
    error: vi.fn(),
    debug: vi.fn(),
  },
}));

describe('ScraperQueueService', () => {
  let service: ScraperQueueService;

  beforeEach(() => {
    service = new ScraperQueueService(3);
    vi.clearAllMocks();
  });

  describe('enqueueJob', () => {
    it('should enqueue a job with default priority', () => {
      const job = service.enqueueJob('source-1');

      expect(job).toBeDefined();
      expect(job.id).toMatch(/^job-/);
      expect(job.sourceId).toBe('source-1');
      expect(job.status).toBe('PENDING');
      expect(job.retryCount).toBe(0);
      expect(job.maxRetries).toBe(3);
      expect(job.priority).toBe(0);
    });

    it('should enqueue a job with custom priority', () => {
      const job = service.enqueueJob('source-1', { priority: 10 });

      expect(job.priority).toBe(10);
    });

    it('should enqueue a job with custom maxRetries', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 5 });

      expect(job.maxRetries).toBe(5);
    });

    it('should generate unique job IDs', () => {
      const job1 = service.enqueueJob('source-1');
      const job2 = service.enqueueJob('source-2');

      expect(job1.id).not.toBe(job2.id);
    });
  });

  describe('dequeueJob', () => {
    it('should return null when queue is empty', () => {
      const job = service.dequeueJob();

      expect(job).toBeNull();
    });

    it('should dequeue the first pending job', () => {
      const enqueuedJob = service.enqueueJob('source-1');
      const dequeuedJob = service.dequeueJob();

      expect(dequeuedJob).toBeDefined();
      expect(dequeuedJob?.id).toBe(enqueuedJob.id);
      expect(dequeuedJob?.status).toBe('RUNNING');
      expect(dequeuedJob?.startedAt).toBeDefined();
    });

    it('should dequeue jobs by priority (higher first)', () => {
      const lowPriorityJob = service.enqueueJob('source-1', { priority: 1 });
      const highPriorityJob = service.enqueueJob('source-2', { priority: 10 });
      const mediumPriorityJob = service.enqueueJob('source-3', { priority: 5 });

      const first = service.dequeueJob();
      const second = service.dequeueJob();
      const third = service.dequeueJob();

      expect(first?.id).toBe(highPriorityJob.id);
      expect(second?.id).toBe(mediumPriorityJob.id);
      expect(third?.id).toBe(lowPriorityJob.id);
    });

    it('should dequeue jobs by creation time when priority is same', () => {
      const job1 = service.enqueueJob('source-1', { priority: 5 });
      const job2 = service.enqueueJob('source-2', { priority: 5 });
      const job3 = service.enqueueJob('source-3', { priority: 5 });

      const first = service.dequeueJob();
      const second = service.dequeueJob();
      const third = service.dequeueJob();

      expect(first?.id).toBe(job1.id);
      expect(second?.id).toBe(job2.id);
      expect(third?.id).toBe(job3.id);
    });

    it('should not dequeue already running jobs', () => {
      service.enqueueJob('source-1');
      const first = service.dequeueJob();
      const second = service.dequeueJob();

      expect(first).toBeDefined();
      expect(second).toBeNull();
    });
  });

  describe('getJobStatus', () => {
    it('should return null for non-existent job', () => {
      const status = service.getJobStatus('non-existent');

      expect(status).toBeNull();
    });

    it('should return job status', () => {
      const job = service.enqueueJob('source-1');
      const status = service.getJobStatus(job.id);

      expect(status).toBeDefined();
      expect(status?.id).toBe(job.id);
      expect(status?.status).toBe('PENDING');
    });
  });

  describe('completeJob', () => {
    it('should mark job as completed', () => {
      const job = service.enqueueJob('source-1');
      service.dequeueJob();
      const completedJob = service.completeJob(job.id, { data: 'result' });

      expect(completedJob.status).toBe('SUCCESS');
      expect(completedJob.completedAt).toBeDefined();
      expect(completedJob.result).toEqual({ data: 'result' });
    });

    it('should throw error for non-existent job', () => {
      expect(() => service.completeJob('non-existent')).toThrow();
    });
  });

  describe('failJob', () => {
    it('should mark job as pending for retry when retries available', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      service.dequeueJob();
      const failedJob = service.failJob(job.id, 'Test error');

      expect(failedJob.status).toBe('PENDING');
      expect(failedJob.retryCount).toBe(1);
      expect(failedJob.error).toBe('Test error');
    });

    it('should mark job as failed when max retries reached', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 0 });
      service.dequeueJob();
      const failedJob = service.failJob(job.id, 'Test error');

      expect(failedJob.status).toBe('FAILED');
      expect(failedJob.completedAt).toBeDefined();
      expect(failedJob.error).toBe('Test error');
    });

    it('should increment retry count on each failure', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      
      service.dequeueJob();
      const firstFail = service.failJob(job.id, 'Error 1');
      expect(firstFail.retryCount).toBe(1);
      expect(firstFail.status).toBe('PENDING');

      service.dequeueJob();
      const secondFail = service.failJob(job.id, 'Error 2');
      expect(secondFail.retryCount).toBe(2);
      expect(secondFail.status).toBe('PENDING');

      service.dequeueJob();
      const thirdFail = service.failJob(job.id, 'Error 3');
      expect(thirdFail.retryCount).toBe(3);
      expect(thirdFail.status).toBe('FAILED');
    });

    it('should throw error for non-existent job', () => {
      expect(() => service.failJob('non-existent', 'error')).toThrow();
    });
  });

  describe('retryJob', () => {
    it('should reset job to pending status', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });
      service.dequeueJob();
      service.failJob(job.id, 'Test error');
      
      const retriedJob = service.retryJob(job.id);

      expect(retriedJob.status).toBe('PENDING');
      expect(retriedJob.retryCount).toBe(2);
      expect(retriedJob.error).toBeUndefined();
    });

    it('should throw error when max retries reached', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 1 });
      service.dequeueJob();
      service.failJob(job.id, 'Error');

      expect(() => service.retryJob(job.id)).toThrow('Job sudah mencapai maksimal retry');
    });

    it('should throw error for non-existent job', () => {
      expect(() => service.retryJob('non-existent')).toThrow();
    });
  });

  describe('cancelJob', () => {
    it('should cancel pending job', () => {
      const job = service.enqueueJob('source-1');
      const cancelledJob = service.cancelJob(job.id);

      expect(cancelledJob.status).toBe('FAILED');
      expect(cancelledJob.error).toBe('Job dibatalkan oleh user');
      expect(cancelledJob.completedAt).toBeDefined();
    });

    it('should cancel running job', () => {
      const job = service.enqueueJob('source-1');
      service.dequeueJob();
      const cancelledJob = service.cancelJob(job.id);

      expect(cancelledJob.status).toBe('FAILED');
      expect(cancelledJob.error).toBe('Job dibatalkan oleh user');
    });

    it('should throw error when cancelling completed job', () => {
      const job = service.enqueueJob('source-1');
      service.dequeueJob();
      service.completeJob(job.id);

      expect(() => service.cancelJob(job.id)).toThrow('Tidak bisa cancel job yang sudah selesai');
    });

    it('should throw error when cancelling failed job', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 0 });
      service.dequeueJob();
      service.failJob(job.id, 'Error');

      expect(() => service.cancelJob(job.id)).toThrow('Tidak bisa cancel job yang sudah selesai');
    });

    it('should throw error for non-existent job', () => {
      expect(() => service.cancelJob('non-existent')).toThrow();
    });
  });

  describe('getQueueStats', () => {
    it('should return correct stats for empty queue', () => {
      const stats = service.getQueueStats();

      expect(stats.total).toBe(0);
      expect(stats.pending).toBe(0);
      expect(stats.running).toBe(0);
      expect(stats.completed).toBe(0);
      expect(stats.failed).toBe(0);
      expect(stats.avgWaitTime).toBe(0);
      expect(stats.avgProcessTime).toBe(0);
    });

    it('should return correct stats with mixed job statuses', () => {
      // Create jobs
      const job1 = service.enqueueJob('source-1');
      const job2 = service.enqueueJob('source-2');
      const job3 = service.enqueueJob('source-3');
      const job4 = service.enqueueJob('source-4', { maxRetries: 0 });

      // Process jobs
      service.dequeueJob(); // job1 running
      service.dequeueJob(); // job2 running
      service.completeJob(job1.id); // job1 completed
      service.dequeueJob(); // job3 running
      service.dequeueJob(); // job4 running
      service.failJob(job4.id, 'Error'); // job4 failed

      const stats = service.getQueueStats();

      expect(stats.total).toBe(4);
      expect(stats.pending).toBe(0);
      expect(stats.running).toBe(2); // job2, job3
      expect(stats.completed).toBe(1); // job1
      expect(stats.failed).toBe(1); // job4
    });

    it('should calculate average wait time correctly', () => {
      service.enqueueJob('source-1');
      
      // Wait a bit
      const start = Date.now();
      while (Date.now() - start < 10) {
        // Small delay
      }
      
      const stats = service.getQueueStats();

      expect(stats.avgWaitTime).toBeGreaterThan(0);
    });
  });

  describe('getAllJobs', () => {
    it('should return all jobs', () => {
      service.enqueueJob('source-1');
      service.enqueueJob('source-2');
      service.enqueueJob('source-3');

      const jobs = service.getAllJobs();

      expect(jobs).toHaveLength(3);
    });

    it('should filter jobs by status', () => {
      const job1 = service.enqueueJob('source-1');
      service.enqueueJob('source-2');
      service.dequeueJob();
      service.completeJob(job1.id);

      const pendingJobs = service.getAllJobs({ status: 'PENDING' });
      const completedJobs = service.getAllJobs({ status: 'SUCCESS' });

      expect(pendingJobs).toHaveLength(1);
      expect(completedJobs).toHaveLength(1);
    });

    it('should filter jobs by sourceId', () => {
      service.enqueueJob('source-1');
      service.enqueueJob('source-1');
      service.enqueueJob('source-2');

      const source1Jobs = service.getAllJobs({ sourceId: 'source-1' });

      expect(source1Jobs).toHaveLength(2);
      expect(source1Jobs.every(j => j.sourceId === 'source-1')).toBe(true);
    });

    it('should sort jobs by creation time (newest first)', () => {
      const job1 = service.enqueueJob('source-1');
      const job2 = service.enqueueJob('source-2');
      const job3 = service.enqueueJob('source-3');

      const jobs = service.getAllJobs();

      expect(jobs[0].id).toBe(job3.id);
      expect(jobs[1].id).toBe(job2.id);
      expect(jobs[2].id).toBe(job1.id);
    });
  });

  describe('clearCompletedJobs', () => {
    it('should clear completed and failed jobs', () => {
      const job1 = service.enqueueJob('source-1');
      const job2 = service.enqueueJob('source-2', { maxRetries: 0 });
      service.enqueueJob('source-3');

      service.dequeueJob();
      service.completeJob(job1.id);
      service.dequeueJob();
      service.failJob(job2.id, 'Error');

      const cleared = service.clearCompletedJobs();

      expect(cleared).toBe(2);
      expect(service.getAllJobs()).toHaveLength(1);
    });

    it('should not clear pending or running jobs', () => {
      service.enqueueJob('source-1');
      const job2 = service.enqueueJob('source-2');
      service.dequeueJob();

      const cleared = service.clearCompletedJobs();

      expect(cleared).toBe(0);
      expect(service.getAllJobs()).toHaveLength(2);
    });
  });

  describe('isQueueFull', () => {
    it('should return false when queue has available slots', () => {
      service.enqueueJob('source-1');
      service.dequeueJob();

      expect(service.isQueueFull()).toBe(false);
    });

    it('should return true when max concurrent jobs reached', () => {
      service.enqueueJob('source-1');
      service.enqueueJob('source-2');
      service.enqueueJob('source-3');
      
      service.dequeueJob();
      service.dequeueJob();
      service.dequeueJob();

      expect(service.isQueueFull()).toBe(true);
    });
  });

  describe('getAvailableSlots', () => {
    it('should return max slots when no jobs running', () => {
      expect(service.getAvailableSlots()).toBe(3);
    });

    it('should return correct available slots', () => {
      service.enqueueJob('source-1');
      service.enqueueJob('source-2');
      
      service.dequeueJob();
      expect(service.getAvailableSlots()).toBe(2);

      service.dequeueJob();
      expect(service.getAvailableSlots()).toBe(1);
    });

    it('should return 0 when queue is full', () => {
      service.enqueueJob('source-1');
      service.enqueueJob('source-2');
      service.enqueueJob('source-3');
      
      service.dequeueJob();
      service.dequeueJob();
      service.dequeueJob();

      expect(service.getAvailableSlots()).toBe(0);
    });
  });

  describe('setMaxConcurrentJobs', () => {
    it('should update max concurrent jobs', () => {
      service.setMaxConcurrentJobs(5);

      expect(service.getAvailableSlots()).toBe(5);
    });

    it('should throw error for invalid value', () => {
      expect(() => service.setMaxConcurrentJobs(0)).toThrow('Max concurrent jobs harus >= 1');
      expect(() => service.setMaxConcurrentJobs(-1)).toThrow('Max concurrent jobs harus >= 1');
    });
  });

  describe('clearAll', () => {
    it('should clear all jobs', () => {
      service.enqueueJob('source-1');
      service.enqueueJob('source-2');
      service.enqueueJob('source-3');

      service.clearAll();

      expect(service.getAllJobs()).toHaveLength(0);
      expect(service.getQueueStats().total).toBe(0);
    });

    it('should clear running jobs', () => {
      service.enqueueJob('source-1');
      service.dequeueJob();

      service.clearAll();

      expect(service.getAllJobs()).toHaveLength(0);
      expect(service.isQueueFull()).toBe(false);
    });
  });

  describe('updateJobProgress', () => {
    it('should update job progress without error', () => {
      const job = service.enqueueJob('source-1');
      service.dequeueJob();

      expect(() => {
        service.updateJobProgress(job.id, {
          percentage: 50,
          message: 'Processing...',
          itemsProcessed: 50,
          totalItems: 100,
        });
      }).not.toThrow();
    });

    it('should throw error for non-existent job', () => {
      expect(() => {
        service.updateJobProgress('non-existent', { percentage: 50 });
      }).toThrow();
    });
  });

  describe('retry logic with exponential backoff', () => {
    it('should handle multiple retries correctly', () => {
      const job = service.enqueueJob('source-1', { maxRetries: 3 });

      // First attempt
      service.dequeueJob();
      const fail1 = service.failJob(job.id, 'Error 1');
      expect(fail1.retryCount).toBe(1);
      expect(fail1.status).toBe('PENDING');

      // Second attempt
      service.dequeueJob();
      const fail2 = service.failJob(job.id, 'Error 2');
      expect(fail2.retryCount).toBe(2);
      expect(fail2.status).toBe('PENDING');

      // Third attempt
      service.dequeueJob();
      const fail3 = service.failJob(job.id, 'Error 3');
      expect(fail3.retryCount).toBe(3);
      expect(fail3.status).toBe('FAILED');
      expect(fail3.completedAt).toBeDefined();
    });
  });

  describe('concurrent job processing', () => {
    it('should respect max concurrent jobs limit', () => {
      const service = new ScraperQueueService(2);

      service.enqueueJob('source-1');
      service.enqueueJob('source-2');
      service.enqueueJob('source-3');

      const job1 = service.dequeueJob();
      const job2 = service.dequeueJob();
      const job3 = service.dequeueJob();

      expect(job1).toBeDefined();
      expect(job2).toBeDefined();
      expect(job3).toBeNull(); // Should not dequeue because limit reached

      expect(service.isQueueFull()).toBe(true);
    });

    it('should allow dequeue after job completion', () => {
      const service = new ScraperQueueService(1);

      const job1 = service.enqueueJob('source-1');
      service.enqueueJob('source-2');

      service.dequeueJob();
      expect(service.isQueueFull()).toBe(true);

      service.completeJob(job1.id);
      expect(service.isQueueFull()).toBe(false);

      const job2 = service.dequeueJob();
      expect(job2).toBeDefined();
    });
  });
});

