## React Hook Example

```typescript
import { useEffect, useState } from 'react';
import io, { Socket } from 'socket.io-client';

interface QueueStats {
  total: number;
  pending: number;
  running: number;
  completed: number;
  failed: number;
  avgWaitTime: number;
  avgProcessTime: number;
}

interface ScraperJob {
  id: string;
  sourceId: string;
  status: string;
  retryCount: number;
  maxRetries: number;
  startedAt?: Date;
  completedAt?: Date;
  createdAt: Date;
  priority: number;
  error?: string;
  result?: any;
}

export function useScraperMonitoring(sourceId?: string) {
  const [socket, setSocket] = useState<Socket | null>(null);
  const [queueStats, setQueueStats] = useState<QueueStats | null>(null);
  const [activeJobs, setActiveJobs] = useState<Map<string, ScraperJob>>(new Map());
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    // Connect to Socket.io
    const newSocket = io('http://localhost:4000');
    setSocket(newSocket);

    // Connection events
    newSocket.on('connect', () => {
      setConnected(true);
      // Subscribe to scraper events
      if (sourceId) {
        newSocket.emit('scraper:subscribe', { sourceId });
      } else {
        newSocket.emit('scraper:subscribe', {});
      }
    });

    newSocket.on('disconnect', () => {
      setConnected(false);
    });

    // Scraper events
    newSocket.on('scraper:job:started', (data) => {
      setActiveJobs(prev => new Map(prev).set(data.job.id, data.job));
      setQueueStats(data.queueStats);
    });

    newSocket.on('scraper:job:progress', (data) => {
      setActiveJobs(prev => {
        const updated = new Map(prev);
        const job = updated.get(data.jobId);
        if (job) {
          updated.set(data.jobId, { ...job, progress: data.progress });
        }
        return updated;
      });
    });

    newSocket.on('scraper:job:completed', (data) => {
      setActiveJobs(prev => {
        const updated = new Map(prev);
        updated.delete(data.job.id);
        return updated;
      });
      setQueueStats(data.queueStats);
    });

    newSocket.on('scraper:job:failed', (data) => {
      if (!data.willRetry) {
        setActiveJobs(prev => {
          const updated = new Map(prev);
          updated.delete(data.job.id);
          return updated;
        });
      }
      setQueueStats(data.queueStats);
    });

    newSocket.on('scraper:queue:updated', (data) => {
      setQueueStats(data.queueStats);
    });

    // Cleanup
    return () => {
      if (sourceId) {
        newSocket.emit('scraper:unsubscribe', { sourceId });
      } else {
        newSocket.emit('scraper:unsubscribe', {});
      }
      newSocket.close();
    };
  }, [sourceId]);

  return {
    socket,
    connected,
    queueStats,
    activeJobs: Array.from(activeJobs.values()),
  };
}
```

