/**
 * Scraper Health Check Service
 * Monitors scraper source availability and health with periodic checks
 */

import { PrismaClient } from '@prisma/client';
import { logger } from './loggerService';
import { scraperSourceService } from './scraperSourceService';
import { createAppError } from '../middleware/errorHandler';
import { ErrorCode } from '../constants/errorCodes';
import { getSocketInstance } from './socketManager';

const prisma = new PrismaClient();

/**
 * Health Status Enum
 */
export enum HealthStatus {
  HEALTHY = 'HEALTHY',
  DEGRADED = 'DEGRADED',
  UNHEALTHY = 'UNHEALTHY',
  UNKNOWN = 'UNKNOWN',
}

/**
 * Health Check Result Interface
 */
export interface HealthCheckResult {
  sourceId: string;
  sourceName: string;
  status: HealthStatus;
  responseTime?: number;
  statusCode?: number;
  error?: string;
  checkedAt: Date;
  consecutiveFailures: number;
  lastSuccessfulCheck?: Date;
  details?: {
    isAccessible: boolean;
    hasValidResponse: boolean;
    meetsPerformanceThreshold: boolean;
  };
}

/**
 * Health Check Configuration
 */
export interface HealthCheckConfig {
  timeout: number; // milliseconds
  performanceThreshold: number; // milliseconds - response time threshold
  degradedThreshold: number; // number of consecutive failures before degraded
  unhealthyThreshold: number; // number of consecutive failures before unhealthy
  checkInterval: number; // milliseconds - interval between automatic checks
}

/**
 * Health Check History Entry
 */
interface HealthCheckHistory {
  sourceId: string;
  consecutiveFailures: number;
  lastSuccessfulCheck?: Date;
  lastCheckTime?: Date;
  lastStatus?: HealthStatus;
}

/**
 * Scraper Health Check Service
 */
export class ScraperHealthCheckService {
  private healthHistory: Map<string, HealthCheckHistory> = new Map();
  private checkIntervals: Map<string, NodeJS.Timeout> = new Map();
  private isAutoCheckEnabled: boolean = false;
  private globalCheckInterval?: NodeJS.Timeout;

  private defaultConfig: HealthCheckConfig = {
    timeout: 10000, // 10 seconds
    performanceThreshold: 3000, // 3 seconds
    degradedThreshold: 2, // 2 consecutive failures = degraded
    unhealthyThreshold: 5, // 5 consecutive failures = unhealthy
    checkInterval: 300000, // 5 minutes
  };

  /**
   * Perform health check on a single source
   */
  async checkSourceHealth(
    sourceId: string,
    config: Partial<HealthCheckConfig> = {}
  ): Promise<HealthCheckResult> {
    const finalConfig: HealthCheckConfig = {
      ...this.defaultConfig,
      ...config,
    };

    try {
      // Get source details
      const source = await scraperSourceService.getSource(sourceId);

      logger.info('Starting health check', {
        sourceId,
        sourceName: source.name,
        url: source.url,
      });

      const startTime = Date.now();
      let status: HealthStatus = HealthStatus.UNKNOWN;
      let statusCode: number | undefined;
      let error: string | undefined;
      let isAccessible = false;
      let hasValidResponse = false;
      let meetsPerformanceThreshold = false;

      try {
        // Perform connectivity test with timeout
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), finalConfig.timeout);

        const response = await fetch(source.url, {
          method: 'HEAD', // Use HEAD for faster checks
          signal: controller.signal,
          headers: source.headers || {},
        });

        clearTimeout(timeoutId);
        const responseTime = Date.now() - startTime;

        statusCode = response.status;
        isAccessible = true;

        // Check if response is valid (2xx or 3xx)
        if (response.ok || (response.status >= 300 && response.status < 400)) {
          hasValidResponse = true;
        }

        // Check performance threshold
        meetsPerformanceThreshold = responseTime <= finalConfig.performanceThreshold;

        // Determine health status
        if (hasValidResponse && meetsPerformanceThreshold) {
          status = HealthStatus.HEALTHY;
        } else if (hasValidResponse && !meetsPerformanceThreshold) {
          status = HealthStatus.DEGRADED;
          error = `Response time (${responseTime}ms) exceeds threshold (${finalConfig.performanceThreshold}ms)`;
        } else {
          status = HealthStatus.UNHEALTHY;
          error = `Invalid response: HTTP ${statusCode}`;
        }

        // Update history on success
        this.updateHealthHistory(sourceId, true);

        // Update source stats
        await scraperSourceService.updateStats(sourceId, true);

        logger.info('Health check completed successfully', {
          sourceId,
          sourceName: source.name,
          status,
          responseTime,
          statusCode,
        });

        const result: HealthCheckResult = {
          sourceId,
          sourceName: source.name,
          status,
          responseTime,
          statusCode,
          error,
          checkedAt: new Date(),
          consecutiveFailures: 0,
          lastSuccessfulCheck: new Date(),
          details: {
            isAccessible,
            hasValidResponse,
            meetsPerformanceThreshold,
          },
        };

        // Emit Socket.io event
        this.emitHealthCheckEvent(result);

        // Update source status in database
        await this.updateSourceHealthStatus(sourceId, status);

        return result;
      } catch (fetchError: any) {
        const responseTime = Date.now() - startTime;

        // Determine error type
        if (fetchError.name === 'AbortError') {
          error = `Timeout after ${finalConfig.timeout}ms`;
          status = HealthStatus.UNHEALTHY;
        } else if (
          fetchError.message.includes('ECONNREFUSED') ||
          fetchError.message.includes('ENOTFOUND') ||
          fetchError.message.includes('ETIMEDOUT')
        ) {
          error = `Connection failed: ${fetchError.message}`;
          status = HealthStatus.UNHEALTHY;
        } else {
          error = fetchError.message || 'Unknown error';
          status = HealthStatus.UNHEALTHY;
        }

        // Update history on failure
        const history = this.updateHealthHistory(sourceId, false);

        // Adjust status based on consecutive failures
        if (history.consecutiveFailures >= finalConfig.unhealthyThreshold) {
          status = HealthStatus.UNHEALTHY;
        } else if (history.consecutiveFailures >= finalConfig.degradedThreshold) {
          status = HealthStatus.DEGRADED;
        }

        // Update source stats
        await scraperSourceService.updateStats(sourceId, false, error);

        logger.warn('Health check failed', {
          sourceId,
          sourceName: source.name,
          status,
          responseTime,
          error,
          consecutiveFailures: history.consecutiveFailures,
        });

        const result: HealthCheckResult = {
          sourceId,
          sourceName: source.name,
          status,
          responseTime,
          error,
          checkedAt: new Date(),
          consecutiveFailures: history.consecutiveFailures,
          lastSuccessfulCheck: history.lastSuccessfulCheck,
          details: {
            isAccessible,
            hasValidResponse,
            meetsPerformanceThreshold,
          },
        };

        // Emit Socket.io event
        this.emitHealthCheckEvent(result);

        // Update source status in database
        await this.updateSourceHealthStatus(sourceId, status, error);

        return result;
      }
    } catch (error) {
      logger.error('Health check error', error as Error, { sourceId });
      throw error;
    }
  }

  /**
   * Check health of all enabled sources
   */
  async checkAllSources(
    config: Partial<HealthCheckConfig> = {}
  ): Promise<HealthCheckResult[]> {
    try {
      logger.info('Starting health check for all enabled sources');

      // Get all enabled sources
      const sources = await scraperSourceService.getEnabledSources();

      logger.info('Checking health for sources', {
        count: sources.length,
        sourceIds: sources.map(s => s.id),
      });

      // Check all sources in parallel
      const results = await Promise.allSettled(
        sources.map(source => this.checkSourceHealth(source.id, config))
      );

      // Process results
      const healthResults: HealthCheckResult[] = [];
      const errors: any[] = [];

      results.forEach((result, index) => {
        if (result.status === 'fulfilled') {
          healthResults.push(result.value);
        } else {
          errors.push({
            sourceId: sources[index].id,
            sourceName: sources[index].name,
            error: result.reason,
          });
        }
      });

      // Log summary
      const summary = {
        total: sources.length,
        healthy: healthResults.filter(r => r.status === HealthStatus.HEALTHY).length,
        degraded: healthResults.filter(r => r.status === HealthStatus.DEGRADED).length,
        unhealthy: healthResults.filter(r => r.status === HealthStatus.UNHEALTHY).length,
        errors: errors.length,
      };

      logger.info('Health check completed for all sources', summary);

      // Emit summary event
      const io = getSocketInstance();
      if (io) {
        io.emit('scraper:health:summary', {
          summary,
          results: healthResults,
          timestamp: new Date(),
        });
      }

      return healthResults;
    } catch (error) {
      logger.error('Failed to check all sources', error as Error);
      throw error;
    }
  }

  /**
   * Start automatic health checks for a source
   */
  startAutoCheck(
    sourceId: string,
    config: Partial<HealthCheckConfig> = {}
  ): void {
    try {
      // Stop existing interval if any
      this.stopAutoCheck(sourceId);

      const finalConfig: HealthCheckConfig = {
        ...this.defaultConfig,
        ...config,
      };

      logger.info('Starting automatic health checks', {
        sourceId,
        interval: finalConfig.checkInterval,
      });

      // Create interval
      const interval = setInterval(async () => {
        try {
          await this.checkSourceHealth(sourceId, finalConfig);
        } catch (error) {
          logger.error('Auto health check failed', error as Error, { sourceId });
        }
      }, finalConfig.checkInterval);

      this.checkIntervals.set(sourceId, interval);

      // Perform initial check
      this.checkSourceHealth(sourceId, finalConfig).catch(error => {
        logger.error('Initial health check failed', error as Error, { sourceId });
      });
    } catch (error) {
      logger.error('Failed to start auto health check', error as Error, { sourceId });
      throw error;
    }
  }

  /**
   * Stop automatic health checks for a source
   */
  stopAutoCheck(sourceId: string): void {
    const interval = this.checkIntervals.get(sourceId);
    if (interval) {
      clearInterval(interval);
      this.checkIntervals.delete(sourceId);
      logger.info('Stopped automatic health checks', { sourceId });
    }
  }

  /**
   * Start automatic health checks for all enabled sources
   */
  async startGlobalAutoCheck(config: Partial<HealthCheckConfig> = {}): Promise<void> {
    try {
      if (this.isAutoCheckEnabled) {
        logger.warn('Global auto health check already enabled');
        return;
      }

      const finalConfig: HealthCheckConfig = {
        ...this.defaultConfig,
        ...config,
      };

      logger.info('Starting global automatic health checks', {
        interval: finalConfig.checkInterval,
      });

      this.isAutoCheckEnabled = true;

      // Create global interval
      this.globalCheckInterval = setInterval(async () => {
        try {
          await this.checkAllSources(finalConfig);
        } catch (error) {
          logger.error('Global auto health check failed', error as Error);
        }
      }, finalConfig.checkInterval);

      // Perform initial check
      await this.checkAllSources(finalConfig);

      logger.info('Global automatic health checks started');
    } catch (error) {
      logger.error('Failed to start global auto health check', error as Error);
      throw error;
    }
  }

  /**
   * Stop automatic health checks for all sources
   */
  stopGlobalAutoCheck(): void {
    if (this.globalCheckInterval) {
      clearInterval(this.globalCheckInterval);
      this.globalCheckInterval = undefined;
      this.isAutoCheckEnabled = false;
      logger.info('Stopped global automatic health checks');
    }

    // Stop all individual intervals
    for (const [sourceId, interval] of this.checkIntervals.entries()) {
      clearInterval(interval);
      this.checkIntervals.delete(sourceId);
    }
  }

  /**
   * Get health status for a source
   */
  getSourceHealthStatus(sourceId: string): HealthCheckHistory | null {
    return this.healthHistory.get(sourceId) || null;
  }

  /**
   * Get health status for all sources
   */
  getAllHealthStatuses(): Map<string, HealthCheckHistory> {
    return new Map(this.healthHistory);
  }

  /**
   * Update health history
   */
  private updateHealthHistory(
    sourceId: string,
    success: boolean
  ): HealthCheckHistory {
    const existing = this.healthHistory.get(sourceId) || {
      sourceId,
      consecutiveFailures: 0,
    };

    if (success) {
      existing.consecutiveFailures = 0;
      existing.lastSuccessfulCheck = new Date();
      existing.lastStatus = HealthStatus.HEALTHY;
    } else {
      existing.consecutiveFailures++;
    }

    existing.lastCheckTime = new Date();

    this.healthHistory.set(sourceId, existing);
    return existing;
  }

  /**
   * Update source health status in database
   */
  private async updateSourceHealthStatus(
    sourceId: string,
    status: HealthStatus,
    error?: string
  ): Promise<void> {
    try {
      const source = await prisma.scraperSource.findUnique({
        where: { id: sourceId },
      });

      if (!source) {
        return;
      }

      const config = (source.config as any) || {};
      const updatedConfig = {
        ...config,
        healthStatus: status,
        lastHealthCheck: new Date().toISOString(),
        ...(error && { lastHealthError: error }),
      };

      // Update status field based on health
      let dbStatus = source.status;
      if (status === HealthStatus.UNHEALTHY) {
        dbStatus = 'Error';
      } else if (status === HealthStatus.DEGRADED) {
        dbStatus = 'Aktif'; // Keep active but with degraded health
      } else if (status === HealthStatus.HEALTHY) {
        dbStatus = 'Aktif';
      }

      await prisma.scraperSource.update({
        where: { id: sourceId },
        data: {
          status: dbStatus,
          config: updatedConfig as any,
        },
      });
    } catch (error) {
      logger.error('Failed to update source health status in database', error as Error, {
        sourceId,
        status,
      });
    }
  }

  /**
   * Emit health check event via Socket.io
   */
  private emitHealthCheckEvent(result: HealthCheckResult): void {
    try {
      const io = getSocketInstance();
      if (io) {
        io.emit('scraper:health:checked', {
          result,
          timestamp: new Date(),
        });
      }
    } catch (error) {
      logger.error('Failed to emit health check event', error as Error);
    }
  }

  /**
   * Get health check statistics
   */
  async getHealthStatistics(): Promise<{
    total: number;
    healthy: number;
    degraded: number;
    unhealthy: number;
    unknown: number;
    averageResponseTime: number;
    sources: Array<{
      id: string;
      name: string;
      status: HealthStatus;
      consecutiveFailures: number;
      lastCheck?: Date;
      lastSuccess?: Date;
    }>;
  }> {
    try {
      const sources = await scraperSourceService.getEnabledSources();
      const stats = {
        total: sources.length,
        healthy: 0,
        degraded: 0,
        unhealthy: 0,
        unknown: 0,
        averageResponseTime: 0,
        sources: [] as any[],
      };

      let totalResponseTime = 0;
      let responseTimeCount = 0;

      for (const source of sources) {
        const history = this.healthHistory.get(source.id);
        const config = (source as any).config || {};
        const healthStatus = config.healthStatus || HealthStatus.UNKNOWN;

        // Count by status
        if (healthStatus === HealthStatus.HEALTHY) stats.healthy++;
        else if (healthStatus === HealthStatus.DEGRADED) stats.degraded++;
        else if (healthStatus === HealthStatus.UNHEALTHY) stats.unhealthy++;
        else stats.unknown++;

        stats.sources.push({
          id: source.id,
          name: source.name,
          status: healthStatus,
          consecutiveFailures: history?.consecutiveFailures || 0,
          lastCheck: history?.lastCheckTime,
          lastSuccess: history?.lastSuccessfulCheck,
        });
      }

      // Calculate average response time from recent logs
      const recentLogs = await prisma.scraperLog.findMany({
        where: {
          status: 'SELESAI',
          startedAt: {
            gte: new Date(Date.now() - 3600000), // Last hour
          },
        },
        select: {
          responseTimeMs: true,
        },
      });

      if (recentLogs.length > 0) {
        totalResponseTime = recentLogs.reduce((sum, log) => sum + log.responseTimeMs, 0);
        stats.averageResponseTime = Math.round(totalResponseTime / recentLogs.length);
      }

      return stats;
    } catch (error) {
      logger.error('Failed to get health statistics', error as Error);
      throw error;
    }
  }

  /**
   * Reset health history for a source
   */
  resetHealthHistory(sourceId: string): void {
    this.healthHistory.delete(sourceId);
    logger.info('Health history reset', { sourceId });
  }

  /**
   * Clear all health history
   */
  clearAllHealthHistory(): void {
    this.healthHistory.clear();
    logger.info('All health history cleared');
  }

  /**
   * Check if auto check is enabled
   */
  isAutoCheckActive(): boolean {
    return this.isAutoCheckEnabled;
  }

  /**
   * Get active check intervals count
   */
  getActiveCheckCount(): number {
    return this.checkIntervals.size;
  }
}

