## 🚀 Quick Start

### 1. Import the Service

```typescript
import { scraperHealthCheckService } from './services/scraperHealthCheckService';
```

### 2. Perform Manual Health Check

```typescript
// Check a single source
const result = await scraperHealthCheckService.checkSourceHealth('source-id');

if (result.status === 'HEALTHY') {
  console.log(`✅ ${result.sourceName} is healthy (${result.responseTime}ms)`);
} else if (result.status === 'DEGRADED') {
  console.log(`⚠️ ${result.sourceName} is degraded: ${result.error}`);
} else {
  console.log(`❌ ${result.sourceName} is unhealthy: ${result.error}`);
}
```

### 3. Start Automatic Monitoring

```typescript
// Start monitoring all enabled sources (checks every 5 minutes)
await scraperHealthCheckService.startGlobalAutoCheck({
  checkInterval: 300000,        // 5 minutes
  performanceThreshold: 3000,   // 3 seconds
  degradedThreshold: 2,         // 2 failures = degraded
  unhealthyThreshold: 5,        // 5 failures = unhealthy
});

// Or monitor a specific source
scraperHealthCheckService.startAutoCheck('source-id', {
  checkInterval: 60000,  // 1 minute
});
```

