## 🎯 Common Use Cases

### Use Case 1: Monitor Critical Sources

```typescript
// Start monitoring for critical sources with aggressive checks
const criticalSources = ['mangadex-id', 'comick-id'];

for (const sourceId of criticalSources) {
  scraperHealthCheckService.startAutoCheck(sourceId, {
    checkInterval: 60000,         // Check every minute
    performanceThreshold: 2000,   // 2 second threshold
    degradedThreshold: 1,         // Degrade after 1 failure
    unhealthyThreshold: 3,        // Unhealthy after 3 failures
  });
}
```

### Use Case 2: Pre-Scrape Health Validation

```typescript
// Check health before running scraper job
async function runScraperWithHealthCheck(sourceId: string) {
  const health = await scraperHealthCheckService.checkSourceHealth(sourceId);
  
  if (health.status === 'UNHEALTHY') {
    throw new Error(`Source ${health.sourceName} is unhealthy: ${health.error}`);
  }
  
  if (health.status === 'DEGRADED') {
    console.warn(`Source ${health.sourceName} is degraded, proceeding with caution`);
  }
  
  // Proceed with scraping
  const job = scraperQueueService.enqueueJob(sourceId);
  return job;
}
```

### Use Case 3: Dashboard Health Overview

```typescript
// Get comprehensive health overview for dashboard
async function getDashboardHealthData() {
  const stats = await scraperHealthCheckService.getHealthStatistics();
  
  return {
    overview: {
      total: stats.total,
      healthy: stats.healthy,
      degraded: stats.degraded,
      unhealthy: stats.unhealthy,
      healthPercentage: (stats.healthy / stats.total) * 100,
    },
    averageResponseTime: stats.averageResponseTime,
    sources: stats.sources.map(source => ({
      id: source.id,
      name: source.name,
      status: source.status,
      statusIcon: getStatusIcon(source.status),
      lastCheck: source.lastCheck,
      issues: source.consecutiveFailures > 0 ? `${source.consecutiveFailures} consecutive failures` : null,
    })),
  };
}

function getStatusIcon(status: string): string {
  switch (status) {
    case 'HEALTHY': return '✅';
    case 'DEGRADED': return '⚠️';
    case 'UNHEALTHY': return '❌';
    default: return '❓';
  }
}
```

### Use Case 4: Automated Recovery

```typescript
// Automatically disable unhealthy sources
socket.on('scraper:health:checked', async (data) => {
  const { result } = data;
  
  if (result.status === 'UNHEALTHY' && result.consecutiveFailures >= 10) {
    console.warn(`Disabling unhealthy source: ${result.sourceName}`);
    
    await scraperSourceService.updateSource(result.sourceId, {
      enabled: false,
    });
    
    // Send alert notification
    await sendAlert({
      type: 'SOURCE_DISABLED',
      sourceId: result.sourceId,
      sourceName: result.sourceName,
      reason: result.error,
    });
  }
});
```

