    it('should select proxy using random strategy', () => {
      const proxy = service.selectProxy(ProxySelectionStrategy.RANDOM);
      expect(proxy).toBeDefined();
    });

    it('should select proxy using priority strategy', () => {
      const proxy = service.selectProxy(ProxySelectionStrategy.PRIORITY);
      expect(proxy).toBeDefined();
      expect(proxy?.priority).toBe(3); // Highest priority
    });

    it('should return null when no active proxies available', () => {
      service.clearAll();
      const proxy = service.selectProxy();
      expect(proxy).toBeNull();
    });

    it('should not select disabled proxies', () => {
      const allProxies = service.getAllProxies();
      allProxies.forEach(p => {
        service.disableProxy(p.id);
      });

      const proxy = service.selectProxy();
      expect(proxy).toBeNull();
    });
  });

  describe('recordSuccess', () => {
    it('should update health metrics on success', () => {
      const proxy = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.recordSuccess(proxy.id, 500);

      const health = service.getProxyHealth(proxy.id);
      expect(health?.consecutiveSuccesses).toBe(1);
      expect(health?.consecutiveFailures).toBe(0);
      expect(health?.totalRequests).toBe(1);
      expect(health?.successfulRequests).toBe(1);
      expect(health?.averageResponseTime).toBe(500);
      expect(health?.isHealthy).toBe(true);
    });

    it('should calculate average response time correctly', () => {
      const proxy = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.recordSuccess(proxy.id, 1000);
      service.recordSuccess(proxy.id, 500);

      const health = service.getProxyHealth(proxy.id);
      expect(health?.averageResponseTime).toBeGreaterThan(0);
      expect(health?.averageResponseTime).toBeLessThan(1000);
    });
  });

  describe('recordFailure', () => {
    it('should update health metrics on failure', () => {
      const proxy = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.recordFailure(proxy.id, 'Connection timeout');

      const health = service.getProxyHealth(proxy.id);
      expect(health?.consecutiveFailures).toBe(1);
      expect(health?.consecutiveSuccesses).toBe(0);
      expect(health?.totalRequests).toBe(1);
      expect(health?.failedRequests).toBe(1);
      expect(health?.lastError).toBe('Connection timeout');
      expect(health?.isHealthy).toBe(false);
    });

    it('should auto-disable proxy after max consecutive failures', () => {
      const proxy = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      // Record 3 consecutive failures
      service.recordFailure(proxy.id, 'Error 1');
      service.recordFailure(proxy.id, 'Error 2');
      service.recordFailure(proxy.id, 'Error 3');

      const updatedProxy = service.getProxy(proxy.id);
      expect(updatedProxy?.status).toBe(ProxyStatus.DISABLED);
    });

    it('should reset consecutive failures on success', () => {
      const proxy = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.recordFailure(proxy.id, 'Error 1');
      service.recordFailure(proxy.id, 'Error 2');
      service.recordSuccess(proxy.id, 500);

      const health = service.getProxyHealth(proxy.id);
      expect(health?.consecutiveFailures).toBe(0);
      expect(health?.consecutiveSuccesses).toBe(1);
    });
  });

  describe('disableProxy and enableProxy', () => {
    it('should disable a proxy', () => {
      const proxy = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.disableProxy(proxy.id);

      const updatedProxy = service.getProxy(proxy.id);
      expect(updatedProxy?.status).toBe(ProxyStatus.DISABLED);

      const health = service.getProxyHealth(proxy.id);
      expect(health?.isHealthy).toBe(false);
    });

    it('should enable a proxy', () => {
      const proxy = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.DISABLED,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.enableProxy(proxy.id);

      const updatedProxy = service.getProxy(proxy.id);
      expect(updatedProxy?.status).toBe(ProxyStatus.ACTIVE);

      const health = service.getProxyHealth(proxy.id);
      expect(health?.isHealthy).toBe(true);
      expect(health?.consecutiveFailures).toBe(0);
    });
  });

  describe('getAllProxies', () => {
    beforeEach(() => {
      service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.addProxy({
        url: 'https://proxy2.example.com:8080',
        type: ProxyType.HTTPS,
        status: ProxyStatus.DISABLED,
        priority: 2,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.addProxy({
        url: 'socks5://proxy3.example.com:1080',
        type: ProxyType.SOCKS5,
        status: ProxyStatus.ACTIVE,
        priority: 3,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });
    });

    it('should return all proxies', () => {
      const proxies = service.getAllProxies();
      expect(proxies).toHaveLength(3);
    });

    it('should filter by status', () => {
      const activeProxies = service.getAllProxies({ status: ProxyStatus.ACTIVE });
      expect(activeProxies).toHaveLength(2);
    });

    it('should filter by type', () => {
      const httpProxies = service.getAllProxies({ type: ProxyType.HTTP });
      expect(httpProxies).toHaveLength(1);
    });

    it('should filter by healthy status', () => {
      const proxies = service.getAllProxies();
      service.recordFailure(proxies[0].id, 'Test error');

      const healthyProxies = service.getAllProxies({ healthyOnly: true });
      expect(healthyProxies.length).toBeLessThan(3);
    });
  });

  describe('getPoolStats', () => {
    it('should return correct pool statistics', () => {
      const proxy1 = service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      const proxy2 = service.addProxy({
        url: 'http://proxy2.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.DISABLED,
        priority: 2,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.recordSuccess(proxy1.id, 500);
      service.recordSuccess(proxy1.id, 600);
      service.recordFailure(proxy1.id, 'Error');

      const stats = service.getPoolStats();

      expect(stats.totalProxies).toBe(2);
      expect(stats.activeProxies).toBe(1);
      expect(stats.disabledProxies).toBe(1);
      expect(stats.totalRequests).toBe(3);
      expect(stats.successfulRequests).toBe(2);
      expect(stats.failedRequests).toBe(1);
      expect(stats.successRate).toBeCloseTo(66.67, 1);
    });

    it('should handle empty pool', () => {
      const stats = service.getPoolStats();

      expect(stats.totalProxies).toBe(0);
      expect(stats.activeProxies).toBe(0);
      expect(stats.totalRequests).toBe(0);
      expect(stats.successRate).toBe(0);
    });
  });

  describe('clearAll', () => {
    it('should clear all proxies from pool', () => {
      service.addProxy({
        url: 'http://proxy1.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 1,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.addProxy({
        url: 'http://proxy2.example.com:8080',
        type: ProxyType.HTTP,
        status: ProxyStatus.ACTIVE,
        priority: 2,
        maxFailures: 3,
        healthCheckInterval: 60000,
        timeout: 10000,
      });

      service.clearAll();

      const proxies = service.getAllProxies();
      expect(proxies).toHaveLength(0);

      const stats = service.getPoolStats();
      expect(stats.totalProxies).toBe(0);
    });
  });

  describe('updatePoolConfig', () => {
    it('should update pool configuration', () => {
      service.updatePoolConfig({
        selectionStrategy: ProxySelectionStrategy.RANDOM,
        maxConsecutiveFailures: 5,
      });

      const config = service.getPoolConfig();
      expect(config.selectionStrategy).toBe(ProxySelectionStrategy.RANDOM);
      expect(config.maxConsecutiveFailures).toBe(5);
    });
  });
});

/**
 * Proxy Management Routes
 * API endpoints for managing proxy pool
 */

import { FastifyInstance, FastifyRequest, FastifyReply } from 'fastify';
import { proxyRotationService, ProxyType, ProxyStatus, ProxySelectionStrategy } from '../services/proxyRotationService';
import { logger } from '../services/loggerService';
import { requireAdmin } from '../middleware/auth';
import { validate } from '../middleware/validation';
import { z } from 'zod';

// Validation schemas
const addProxySchema = z.object({
  url: z.string().url('URL proxy tidak valid'),
  type: z.nativeEnum(ProxyType),
  priority: z.number().int().min(0).default(1),
  maxFailures: z.number().int().min(1).default(3),
  healthCheckInterval: z.number().int().min(60000).default(300000), // Min 1 minute
  timeout: z.number().int().min(1000).default(30000),
});

const updateProxySchema = z.object({
  priority: z.number().int().min(0).optional(),
  maxFailures: z.number().int().min(1).optional(),
  healthCheckInterval: z.number().int().min(60000).optional(),
  timeout: z.number().int().min(1000).optional(),
  status: z.nativeEnum(ProxyStatus).optional(),
});

const updatePoolConfigSchema = z.object({
  selectionStrategy: z.nativeEnum(ProxySelectionStrategy).optional(),
  healthCheckEnabled: z.boolean().optional(),
  healthCheckInterval: z.number().int().min(60000).optional(),
  autoDisableOnFailure: z.boolean().optional(),
  maxConsecutiveFailures: z.number().int().min(1).optional(),
  reEnableAfter: z.number().int().min(0).optional(),
});

const idParamSchema = z.object({
  id: z.string().min(1),
});

/**
 * Proxy Management Routes
 */
export async function proxyManagementRoutes(fastify: FastifyInstance) {
  /**
   * POST /api/admin/proxies
   * Add new proxy to pool
   */
  fastify.post(
    '/api/admin/proxies',
    {
      preHandler: [
        requireAdmin,
        validate({
          body: addProxySchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const body = request.body as z.infer<typeof addProxySchema>;
        const user = request.user as { id: string; role: string };

        const proxy = proxyRotationService.addProxy({
          url: body.url,
          type: body.type,
          status: ProxyStatus.ACTIVE,
          priority: body.priority,
          maxFailures: body.maxFailures,
          healthCheckInterval: body.healthCheckInterval,
          timeout: body.timeout,
        });

        logger.info('Proxy added via API', {
          proxyId: proxy.id,
          userId: user.id,
        });

        return reply.status(201).send({
          success: true,
          data: proxy,
        });
      } catch (error) {
        logger.error('Failed to add proxy via API', error as Error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/proxies
   * List all proxies
   */
  fastify.get(
    '/api/admin/proxies',
    {
      preHandler: [requireAdmin],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const query = request.query as any;

        const filters: any = {};
        if (query.status) filters.status = query.status as ProxyStatus;
        if (query.type) filters.type = query.type as ProxyType;
        if (query.healthyOnly === 'true') filters.healthyOnly = true;

        const proxies = proxyRotationService.getAllProxies(filters);

        return reply.send({
          success: true,
          data: proxies,
          meta: {
            total: proxies.length,
          },
        });
      } catch (error) {
        logger.error('Failed to list proxies via API', error as Error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/proxies/:id
   * Get single proxy
   */
  fastify.get(
    '/api/admin/proxies/:id',
    {
      preHandler: [
        requireAdmin,
        validate({
          params: idParamSchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const { id } = request.params as { id: string };

        const proxy = proxyRotationService.getProxy(id);
        if (!proxy) {
          return reply.status(404).send({
            success: false,
            error: {
              code: 'NOT_FOUND',
              message: 'Proxy tidak ditemukan',
            },
          });
        }

        const health = proxyRotationService.getProxyHealth(id);

        return reply.send({
          success: true,
          data: {
            proxy,
            health,
          },
        });
      } catch (error) {
        logger.error('Failed to get proxy via API', error as Error, {
          userId: (request.user as any)?.id,
          proxyId: (request.params as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * PUT /api/admin/proxies/:id
   * Update proxy configuration
   */
  fastify.put(
    '/api/admin/proxies/:id',
    {
      preHandler: [
        requireAdmin,
        validate({
          params: idParamSchema,
          body: updateProxySchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const { id } = request.params as { id: string };
        const body = request.body as z.infer<typeof updateProxySchema>;
        const user = request.user as { id: string; role: string };

        const proxy = proxyRotationService.updateProxy(id, body);

        logger.info('Proxy updated via API', {
          proxyId: id,
          userId: user.id,
          updates: Object.keys(body),
        });

        return reply.send({
          success: true,
          data: proxy,
        });
      } catch (error) {
        logger.error('Failed to update proxy via API', error as Error, {
          userId: (request.user as any)?.id,
          proxyId: (request.params as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * DELETE /api/admin/proxies/:id
   * Remove proxy from pool
   */
  fastify.delete(
    '/api/admin/proxies/:id',
    {
      preHandler: [
        requireAdmin,
        validate({
          params: idParamSchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const { id } = request.params as { id: string };
        const user = request.user as { id: string; role: string };

        proxyRotationService.removeProxy(id);

        logger.info('Proxy removed via API', {
          proxyId: id,
          userId: user.id,
        });

        return reply.send({
          success: true,
          message: 'Proxy berhasil dihapus',
        });
      } catch (error) {
        logger.error('Failed to remove proxy via API', error as Error, {
          userId: (request.user as any)?.id,
          proxyId: (request.params as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * POST /api/admin/proxies/:id/test
   * Test proxy connectivity
   */
  fastify.post(
    '/api/admin/proxies/:id/test',
    {
      preHandler: [
        requireAdmin,
        validate({
          params: idParamSchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const { id } = request.params as { id: string };
        const body = request.body as any;
        const user = request.user as { id: string; role: string };

        const result = await proxyRotationService.testProxy(
          id,
          body?.testUrl || 'https://www.google.com'
        );

        logger.info('Proxy tested via API', {
          proxyId: id,
          userId: user.id,
          success: result.success,
        });

        return reply.send({
          success: true,
          data: result,
        });
      } catch (error) {
        logger.error('Failed to test proxy via API', error as Error, {
          userId: (request.user as any)?.id,
          proxyId: (request.params as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * POST /api/admin/proxies/:id/enable
   * Enable proxy
   */
  fastify.post(
    '/api/admin/proxies/:id/enable',
    {
      preHandler: [
        requireAdmin,
        validate({
          params: idParamSchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const { id } = request.params as { id: string };
        const user = request.user as { id: string; role: string };

        proxyRotationService.enableProxy(id);

        logger.info('Proxy enabled via API', {
          proxyId: id,
          userId: user.id,
        });

        return reply.send({
          success: true,
          message: 'Proxy berhasil diaktifkan',
        });
      } catch (error) {
        logger.error('Failed to enable proxy via API', error as Error, {
          userId: (request.user as any)?.id,
          proxyId: (request.params as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * POST /api/admin/proxies/:id/disable
   * Disable proxy
   */
  fastify.post(
    '/api/admin/proxies/:id/disable',
    {
      preHandler: [
        requireAdmin,
        validate({
          params: idParamSchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const { id } = request.params as { id: string };
        const body = request.body as any;
        const user = request.user as { id: string; role: string };

        proxyRotationService.disableProxy(id, body?.reason);

        logger.info('Proxy disabled via API', {
          proxyId: id,
          userId: user.id,
          reason: body?.reason,
        });

        return reply.send({
          success: true,
          message: 'Proxy berhasil dinonaktifkan',
        });
      } catch (error) {
        logger.error('Failed to disable proxy via API', error as Error, {
          userId: (request.user as any)?.id,
          proxyId: (request.params as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/proxies/health/all
   * Get health metrics for all proxies
   */
  fastify.get(
    '/api/admin/proxies/health/all',
    {
      preHandler: [requireAdmin],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const healthMetrics = proxyRotationService.getAllProxyHealth();

        return reply.send({
          success: true,
          data: healthMetrics,
        });
      } catch (error) {
        logger.error('Failed to get proxy health metrics via API', error as Error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/proxies/stats/pool
   * Get proxy pool statistics
   */
  fastify.get(
    '/api/admin/proxies/stats/pool',
    {
      preHandler: [requireAdmin],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const stats = proxyRotationService.getPoolStats();

        return reply.send({
          success: true,
          data: stats,
        });
      } catch (error) {
        logger.error('Failed to get pool stats via API', error as Error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * GET /api/admin/proxies/config/pool
   * Get proxy pool configuration
   */
  fastify.get(
    '/api/admin/proxies/config/pool',
    {
      preHandler: [requireAdmin],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const config = proxyRotationService.getPoolConfig();

        return reply.send({
          success: true,
          data: config,
        });
      } catch (error) {
        logger.error('Failed to get pool config via API', error as Error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * PUT /api/admin/proxies/config/pool
   * Update proxy pool configuration
   */
  fastify.put(
    '/api/admin/proxies/config/pool',
    {
      preHandler: [
        requireAdmin,
        validate({
          body: updatePoolConfigSchema,
        }),
      ],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const body = request.body as z.infer<typeof updatePoolConfigSchema>;
        const user = request.user as { id: string; role: string };

        proxyRotationService.updatePoolConfig(body);

        logger.info('Pool config updated via API', {
          userId: user.id,
          updates: Object.keys(body),
        });

        return reply.send({
          success: true,
          message: 'Konfigurasi pool berhasil diupdate',
          data: proxyRotationService.getPoolConfig(),
        });
      } catch (error) {
        logger.error('Failed to update pool config via API', error as Error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
    }
  );

  /**
   * DELETE /api/admin/proxies/pool/clear
   * Clear all proxies from pool
   */
  fastify.delete(
    '/api/admin/proxies/pool/clear',
    {
      preHandler: [requireAdmin],
    },
    async (request: FastifyRequest, reply: FastifyReply) => {
      try {
        const user = request.user as { id: string; role: string };

        proxyRotationService.clearAll();

        logger.info('Proxy pool cleared via API', {
          userId: user.id,
        });

        return reply.send({
          success: true,
          message: 'Semua proxy berhasil dihapus dari pool',
        });
      } catch (error) {
        logger.error('Failed to clear proxy pool via API', error as Error, {
          userId: (request.user as any)?.id,
        });
        throw error;
      }
    }
  );
}

